features.snippet:
interface bus_if (input logic clk);
    logic [31:0] addr;
    logic [31:0] data;
    clocking cb @(posedge clk);
        default input #1step output #0;
        input read_data;
        output addr, data;
    endclocking
    modport master (input read_data, output addr, data);
    modport tb (input clk, clocking cb);
endinterface
